import{EVE_ROUTE_PREFIX}from"#protocol/routes.js";import{UnknownDevScheduleError,dispatchScheduleInDev}from"#internal/nitro/host/dispatch-schedule-in-dev.js";const DEV_DISPATCH_SCHEDULE_PATH_PATTERN=RegExp(`^${EVE_ROUTE_PREFIX.replace(/\//g,`\\/`)}\\/dev\\/schedules\\/([^/]+)$`);async function handleDevScheduleDispatchRequest(e,n){let r=new URL(n.url).pathname.match(DEV_DISPATCH_SCHEDULE_PATH_PATTERN)?.[1];if(typeof r!=`string`||r.length===0)return Response.json({error:`Missing schedule id.`},{status:400});let i;try{i=decodeURIComponent(r)}catch{return Response.json({error:`Schedule id is not a valid URI component.`},{status:400})}if(i.length===0)return Response.json({error:`Missing schedule id.`},{status:400});try{let t=await dispatchScheduleInDev({appRoot:e.appRoot,scheduleId:i});return Response.json({scheduleId:t.scheduleId,sessionIds:t.sessionIds})}catch(e){if(e instanceof UnknownDevScheduleError)return Response.json({error:e.message,availableScheduleIds:e.availableScheduleIds},{status:404});throw e}}export{handleDevScheduleDispatchRequest};